            <Route path="/feedback/my-tasks" element={<MyTasksPage />} />
            <Route path="/feedback/assignments/:assignmentId" element={<FeedbackFormPage />} />
            <Route path="/feedback/my-result" element={<EmployeeResultPage />} />
            <Route path="/feedback/team-summary" element={<ManagerSummaryPage />} />
          </Route>
          <Route element={<EmployeeLayout />}>
            <Route path="/employee/dashboard" element={<EmployeeDashboard />} />
          </Route>


          <Route element={<HRLayout />}>
            <Route path="/" element={<Navigate to="/dashboard" replace />} />
            <Route path="/dashboard" element={<Home />} />
            <Route path="/hr/profile" element={<ProfilePage />} />

            <Route path="/hr/employee" element={<EmployeeManagement />} />
            <Route path="/hr/employee/workforce" element={<EmployeeDashboard />} />
            <Route path="/hr/employee/create" element={<CreateEmployeeAccount />} />
            <Route path="/hr/employee/import" element={<HrEmployeeAccountImport />} />
            <Route path="/hr/team" element={<TeamManagement />} />
            <Route path="/hr/team/create" element={<TeamCreate />} />
            <Route path="/hr/department" element={<DepartmentManagement />} />

            <Route path="/permissions" element={<Permissions />} />
            <Route path="/user-roles" element={<UserRoles />} />
            <Route path="/role-permissions" element={<RolePermissions />} />

            <Route path="/pip-updates" element={<PipUpdates />} />
            <Route path="/notifications" element={<NotificationTemplates />} />
            <Route path="/one-on-one-meetings" element={<OneOnOneMeetings />} />
            <Route path="/one-on-one-action-items" element={<OneOnOneActionItems />} />

            <Route path="/hr/position/create" element={<PositionCreate />} />
            <Route path="/hr/position-level/create" element={<PositionLevelCreate />} />
            <Route path="/hr/position/table" element={<PositionTable />} />

            <Route path="/hr/performance-kpi/unit" element={<KpiUnitPage />} />
            <Route path="/hr/performance-kpi/category" element={<KpiCategoryPage />} />
            <Route path="/hr/performance-kpi/item" element={<KpiItemPage />} />
            <Route path="/hr/performance-kpi/form" element={<KpiFormPage />} />

            {/* 360 Feedback — HR Dashboard (new wizard) */}
            <Route path="/hr/feedback/dashboard" element={<HrFeedbackDashboard />} />
            {/* Keep old routes for backward compatibility */}
            <Route path="/hr/feedback/campaigns/setup" element={<CreateCampaignPage />} />
            <Route path="/hr/feedback/analytics" element={<FeedbackAnalyticsPage />} />
            <Route path="/hr/feedback/forms" element={<FeedbackFormsPage />} />
            <Route path="/hr/feedback/campaigns" element={<FeedbackCampaignsPage />} />
          </Route>
        </Route>

        <Route path="*" element={<Navigate to="/login" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;

import { useEffect, useState } from 'react';
import { NavLink, useLocation, useNavigate } from 'react-router-dom';
import { authStorage } from '../../services/authStorage';
import './hr-layout.css';

type SidebarProps = {
  collapsed: boolean;
  onToggle: () => void;
};

type NavItem = {
  to: string;
  label: string;
  icon: string;
  /** When set on a child link, only exact path matches (avoids e.g. /hr/employee matching /hr/employee/create). */
  end?: boolean;
  children?: NavItem[];
};

const Sidebar = ({ collapsed, onToggle }: SidebarProps) => {
  const navigate = useNavigate();
  const location = useLocation();
  const user = authStorage.getUser();
  const dashboard = user?.dashboard ?? '';

  const roleLabel =
    dashboard === 'EMPLOYEE_DASHBOARD'
      ? 'Employee'
      : dashboard === 'HR_DASHBOARD'
      ? 'HR'
      : dashboard === 'ADMIN_DASHBOARD'
      ? 'Admin'
      : dashboard === 'MANAGER_DASHBOARD'
      ? 'Manager'
      : dashboard === 'DEPARTMENT_HEAD_DASHBOARD'
      ? 'Department Head'
      : dashboard === 'EXECUTIVE_DASHBOARD'
      ? 'Executive'
      : 'User';

  const navItems: NavItem[] =
    dashboard === 'EMPLOYEE_DASHBOARD'
      ? [{ to: '/employee/dashboard', label: 'Dashboard', icon: 'bi bi-grid-1x2' }]
      : [
          { to: '/dashboard', label: 'Dashboard', icon: 'bi bi-grid-1x2' },

          {
            to: '/hr/team',
            label: 'Team Management',
            icon: 'bi bi-people',
            children: [
              { to: '/hr/team', label: 'Teams', icon: 'bi bi-people', end: true },
              { to: '/hr/team/create', label: 'Create Team', icon: 'bi bi-plus-circle' },
            ],
          },

          {
            to: '/hr/organization',
            label: 'Organization',
            icon: 'bi bi-building',
            children: [
              { to: '/hr/department', label: 'Departments', icon: 'bi bi-building' },
              { to: '/hr/employee', label: 'Employee list', icon: 'bi bi-people', end: true },
              {
                to: '/hr/employee/workforce',
                label: 'Workforce overview',
                icon: 'bi bi-person-badge',
                end: true,
              },
              { to: '/hr/employee/create', label: 'Create Employee', icon: 'bi bi-person-plus' },
              { to: '/hr/employee/import', label: 'Import Employees', icon: 'bi bi-upload' },
            ],
          },

          {
            to: '/user-roles',
            label: 'Access Control',
            icon: 'bi bi-shield-lock',
            children: [
              { to: '/user-roles', label: 'User Roles', icon: 'bi bi-person-gear' },
              { to: '/role-permissions', label: 'Role Permissions', icon: 'bi bi-shield-check' },
              { to: '/permissions', label: 'Permissions', icon: 'bi bi-key' },
            ],
          },

          {
            to: '/pip-updates',
            label: 'One-on-One',
            icon: 'bi bi-chat-left-text',
            children: [
              { to: '/pip-updates', label: 'PIP Updates', icon: 'bi bi-clipboard-check' },
              { to: '/one-on-one-meetings', label: '1:1 Meetings', icon: 'bi bi-chat-dots' },
              { to: '/one-on-one-action-items', label: 'Action Items', icon: 'bi bi-list-check' },
            ],
          },

          { to: '/notifications', label: 'Notifications', icon: 'bi bi-bell' },

          {
            to: '/hr/position/create',
            label: 'Positions',
            icon: 'bi bi-briefcase',
            children: [
              { to: '/hr/position/create', label: 'Create Position', icon: 'bi bi-briefcase' },
              { to: '/hr/position-level/create', label: 'Position Levels', icon: 'bi bi-diagram-3' },
              { to: '/hr/position/table', label: 'Positions Table', icon: 'bi bi-table' },
            ],
          },

          {
            to: '/hr/performance-kpi/unit',
            label: 'KPI Management',
            icon: 'bi bi-speedometer2',
            children: [
              { to: '/hr/performance-kpi/unit', label: 'KPI Units', icon: 'bi bi-speedometer2' },
              { to: '/hr/performance-kpi/category', label: 'KPI Categories', icon: 'bi bi-tags' },
              { to: '/hr/performance-kpi/item', label: 'KPI Items', icon: 'bi bi-card-checklist' },
              { to: '/hr/performance-kpi/form', label: 'KPI Forms', icon: 'bi bi-ui-checks-grid' },
            ],
          },
        ];

  const hasActiveChild = (item: NavItem) =>
    item.children?.some((child) => location.pathname.startsWith(child.to)) ?? false;

  const [expanded, setExpanded] = useState<Set<string>>(new Set());

  useEffect(() => {
    setExpanded((prev) => {
      const next = new Set(prev);
      navItems.forEach((item) => {
        if (hasActiveChild(item)) next.add(item.to);
      });
      return next;
    });
  }, [location.pathname]);

  const isParentActive = (item: NavItem) =>
    location.pathname.startsWith(item.to) || hasActiveChild(item);

  const toggleParent = (item: NavItem) => {
    if (!item.children?.length) {
      navigate(item.to);
      return;
    }
    setExpanded((prev) => {
      const next = new Set(prev);
      if (next.has(item.to)) next.delete(item.to);
      else next.add(item.to);
      return next;
    });
  };

  return (
    <aside className={`hr-sidebar ${collapsed ? 'collapsed' : ''}`}>
      <div className="hr-sidebar-top">
        <div className="hr-brand">
          <div className="hr-brand-mark">E</div>

          {!collapsed && (
            <div className="hr-brand-copy">
              <h2>EPMS</h2>
              <p>Performance System</p>
            </div>
          )}
        </div>

        {!collapsed && <div className="hr-sidebar-top-divider" />}
      </div>

      {!collapsed && (
        <div className="hr-role-chip">
          <small>CURRENT ROLE</small>
          <strong>{roleLabel}</strong>
        </div>
      )}

      <nav className="hr-nav">
        {navItems.map((item) => {
          const isExpanded = expanded.has(item.to);
          const parentActive = isParentActive(item);

          if (!item.children?.length) {
            return (
              <NavLink
                key={item.to}
                to={item.to}
                className={({ isActive }) => `hr-nav-link ${isActive ? 'active' : ''}`}
                title={collapsed ? item.label : undefined}
              >
                <i className={item.icon} />
                {!collapsed && <span>{item.label}</span>}
              </NavLink>
            );
          }

          return (
            <div key={item.to} className="hr-nav-group">
              <button
                type="button"
                className={`hr-nav-link hr-nav-group-toggle ${parentActive ? 'active' : ''}`}
                onClick={() => toggleParent(item)}
                title={collapsed ? item.label : undefined}
              >
                <i className={item.icon} />
                {!collapsed && (
                  <>
                    <span>{item.label}</span>
                    <i
                      className={`bi ${
                        isExpanded ? 'bi-chevron-down' : 'bi-chevron-right'
                      } hr-submenu-caret`}
                    />
                  </>
                )}
              </button>

              {!collapsed && isExpanded && (
                <div className="hr-submenu">
                  {item.children.map((child) => (
                    <NavLink
                      key={child.to}
                      to={child.to}
                      end={child.end}
                      className={({ isActive }) =>
                        `hr-submenu-link ${isActive ? 'active' : ''}`
                      }
                    >
                      <i className={child.icon} />
                      <span>{child.label}</span>
                    </NavLink>
                  ))}
                </div>
              )}
            </div>
          );
        })}
      </nav>

      <div className="hr-sidebar-footer">
        <button
          type="button"
          className="hr-sidebar-collapse"
          onClick={onToggle}
          aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        >
          <i className={`bi ${collapsed ? 'bi-chevron-right' : 'bi-chevron-left'}`} />
          {!collapsed && <span>Collapse</span>}
        </button>
      </div>
    </aside>
  );
};

export default Sidebar;

